class _StrictLoader(yaml.SafeLoader):
    """SafeLoader that rejects duplicate mapping keys.

    PyYAML follows the permissive reading of the spec: a repeated key silently
    overrides the earlier one, so a config with two `folders:` blocks loads fine
    and only the last one takes effect. In a config file that is always a user
    mistake, so report it as a parse error.

    Subclassing keeps the change local; registering it on `SafeLoader` would
    apply to every `yaml.safe_load` in the process.
    """

    @override
    def construct_mapping(self, node: yaml.MappingNode, deep: bool = False) -> dict[Any, Any]:
        seen: set[Any] = set()
        for key_node, _ in node.value:
            key = self.construct_object(key_node, deep=deep)
            if not isinstance(key, Hashable):
                continue  # super() reports unhashable keys
            if key in seen:
                raise yaml.constructor.ConstructorError(
                    "while constructing a mapping",
                    node.start_mark,
                    f"found duplicate key {key!r}",
                    key_node.start_mark,
                )
            seen.add(key)
        return super().construct_mapping(node, deep)

@classmethod
@override
def validate_config(cls, config: dict[str, Any]) -> list[ConfigError]:
    """Validate config schema, then that every folder path is absolute.

    `path` is handed to rsync verbatim — no `~`/env expansion, unlike
    `filter_file` — so a relative path silently resolves against the working
    directory of each side and mirrors the wrong tree.
    """
    errors = super().validate_config(config)
    if errors:
        return errors  # Don't continue if schema is invalid

    for index, folder in enumerate(config["folders"]):
        if not PurePosixPath(folder["path"]).is_absolute():
            errors.append(
                ConfigError(
                    job=cls.name,
                    path=f"folders.{index}.path",
                    message=f"Folder path must be absolute: {folder['path']!r}",
                )
            )

    return errors

